#include <iostream>
#include <stdexcept>
using namespace std;

int divide(int a, int b) {
    if (b == 0) {
        throw runtime_error("Division by zero!");
    }
    return a / b;
}

int main() {
    int x = 10, y = 0;
    try {
        int result = divide(x, y);
        cout << "Result: " << result << endl;
    }
    catch (runtime_error& e) {
        cout << "Exception caught: " << e.what() << endl;
    }
    catch (exception& e) {
        cout << "General exception: " << e.what() << endl;
    }
    catch (...) {
        cout << "Unknown exception caught" << endl;
    }
    return 0;
}

#include <iostream>
#include <exception>
using namespace std;

class MyException : public exception {
private:
    string msg;
public:
    MyException(const string& message) : msg(message) {}
    const char* what() const noexcept override {
        return msg.c_str();
    }
};

void checkAge(int age) {
    if (age < 0)
        throw MyException("Age cannot be negative!");
    if (age > 150)
        throw MyException("Age is unrealistic!");
}

int main() {
    try {
        checkAge(-5);
    }
    catch (MyException& e) {
        cout << "Custom Exception: " << e.what() << endl;
    }
    return 0;
}

#include <iostream>
using namespace std;

class Resource {
public:
    Resource(int id) : id(id) {
        if (id < 0)
            throw runtime_error("Invalid resource ID");
        cout << "Resource " << id << " created" << endl;
    }
    ~Resource() {
        cout << "Resource " << id << " destroyed" << endl;
    }
};

class Manager {
    Resource* ptr;
public:
    Manager(int id) : ptr(nullptr) {
        try {
            ptr = new Resource(id);
        }
        catch (...) {
            cout << "Constructor failed, cleaning up" << endl;
            throw; // Rethrow the exception
        }
    }
    ~Manager() {
        if (ptr) delete ptr;
    }
};

int main() {
    try {
        Manager m(-1); // Will throw
    }
    catch (runtime_error& e) {
        cout << "Caught: " << e.what() << endl;
    }
    return 0;
}

#include <iostream>
using namespace std;

class Test {
    int id;
public:
    Test(int i) : id(i) {
        cout << "Object " << id << " constructed" << endl;
    }
    ~Test() {
        cout << "Object " << id << " destroyed" << endl;
    }
};

void func3() {
    Test t(3);
    throw runtime_error("Error in func3");
}

void func2() {
    Test t(2);
    func3();
}

void func1() {
    Test t(1);
    func2();
}

int main() {
    try {
        func1();
    }
    catch (exception& e) {
        cout << "Caught: " << e.what() << endl;
    }
    return 0;
}
